  ('locality-6e11b43e-moex-00198', 'locality-6e11b43e', 'locality-6e11b43e-moex-111-3a7b2121', 'sub-locality-6e11b43e-02', NULL, 'single_choice', '我國衛生福利部成立之後，將原屬內政部的社會福利業務移撥至該部的作法，稱為：', '["組織改造", "流程簡化", "人員精簡", "協力治理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:31+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "304", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "原住民族行政"}'::jsonb, NULL),
